mapper.sql:


where 1 = 1



    and  pe.id = #{criteria.employeeId,jdbcType=BIGINT}


    and exists (SELECT 1
                         FROM pm_employee_job pej_t
                        WHERE pej_t.employee_id = pe.ID
                          AND pej_t.enabled_flag = 1
                          AND pej_t.job_main_flag = 1
                          AND pej_t.dept_id IN 


           #{item, jdbcType=BIGINT}


    )





             and pe.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}




             and fdev.ext_dept_name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}




             and fdev.ext_department_name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}




             and fdev.ext_team_name ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}




             and tt.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=TIMESTAMP}




             and tt.${criteria.column} ${criteria.symbol} #{criteria.value,jdbcType=VARCHAR}

mapper.select:
select tt.employee_id as tt_employee_id, fdev.ext_dept_name AS tt_pe_dept_name, fdev.ext_department_name AS tt_pe_department, fdev.ext_team_name AS tt_pe_team, tt_pe.work_card AS tt_pe_work_card, tt_pe.name AS tt_pe_name,tt_pe.id AS tt_pe_id, tt_pe.leave_flag AS tt_pe_leave_flag, tp.training_name AS tp_training_name, tp.id AS tp_id,
from (select distinct employee_id from td_teacher union all select distinct employee_id from td_plan_employee where enabled_flag = 1 and type = 'teacher' and employee_id not in (select distinct employee_id from td_teacher)) tt join pm_employee tt_pe on tt.employee_id = tt_pe.id and tt_pe.enabled_flag = 1 join td_plan_employee tpe on tt.employee_id = tpe.employee_id and tpe.enabled_flag = 1 and tpe.type = 'teacher' join td_plan_implement tpi on tpe.plan_implement_id = tpi.id and tpi.approval_status = '已完成' join td_plan tp on tpi.plan_id = tp.id left outer join pm_employee_job pej on tt_pe.id = pej.employee_id and pej.job_main_flag = 1 and pej.enabled_flag = 1 left outer join fnd_dept_ext_v fdev on pej.dept_id = fdev.id and fdev.enabled_flag = 1 and fdev.deleted_flag = 0 where 1= 1
and tpi.begin_date >= #{criteria.beginDate,jdbcType=TIMESTAMP}
and tpi.end_date <= #{criteria.endDate,jdbcType=TIMESTAMP}
